#!/usr/bin/env python3
# Run this as a background daemon on the VM to respond to maintenance events
import json, time, urllib.request, signal, sys

IMDS_URL = "http://169.254.169.254/metadata/scheduledevents?api-version=2020-07-01"
CHECK_INTERVAL_SECS = 15

def get_scheduled_events():
    req = urllib.request.Request(IMDS_URL, headers={"Metadata": "true"})
    with urllib.request.urlopen(req, timeout=5) as resp:
        return json.load(resp)

def handle_event(event):
    etype = event.get("EventType")
    if etype in ("Reboot", "Redeploy", "Freeze"):
        print(f"[MAINTENANCE] Event: {etype}, NotBefore: {event.get('NotBefore')}")
        # Custom drain logic here:
        # - Stop accepting new requests (remove from LB backend pool via IMDS or external API)
        # - Wait for in-flight requests to drain
        # - Checkpoint any stateful processing
        # - Acknowledge event to shorten the NotBefore window
        acknowledge_event(event["EventId"], event.get("DocumentIncarnation", 1))

def acknowledge_event(event_id, incarnation):
    body = json.dumps({
        "StartRequests": [{"EventId": event_id}],
        "DocumentIncarnation": incarnation
    }).encode()
    req = urllib.request.Request(IMDS_URL, data=body, method="POST",
                                  headers={"Metadata": "true", "Content-Type": "application/json"})
    urllib.request.urlopen(req, timeout=5)
    print(f"[MAINTENANCE] Acknowledged event {event_id}")

while True:
    try:
        data = get_scheduled_events()
        for event in data.get("Events", []):
            handle_event(event)
    except Exception as e:
        print(f"[WARN] Error polling IMDS: {e}")
    time.sleep(CHECK_INTERVAL_SECS)

// Availability Set with explicit update and fault domain counts
resource availabilitySet 'Microsoft.Compute/availabilitySets@2023-03-01' = {
  name: 'myAS'
  location: location
  sku: {
    name: 'Aligned'   // Required for managed disk fault domain alignment
  }
  properties: {
    platformFaultDomainCount: 3
    platformUpdateDomainCount: 5   // 5 UDs = at most 1/5 of VMs offline during maintenance
  }
}
